/**
 * Generated by `createservice acquiring.RegisterExternalPaymentsService`
 */
const { checkDvAndSender } = require('@open-condo/keystone/plugins/dvAndSender')
const { GQLCustomSchema } = require('@open-condo/keystone/schema')

const access = require('@condo/domains/acquiring/access/RegisterExternalPaymentsService')
const { REGISTER_EXTERNAL_PAYMENTS_ERRORS: ERRORS } = require('@condo/domains/acquiring/constants/registerExternalPaymentsErrors')
const { Payment, MultiPayment } = require('@condo/domains/acquiring/utils/serverSchema')
const {
    buildPaymentCreateInput,
    buildMultiPaymentCreateInput,
} = require('@condo/domains/acquiring/utils/serverSchema/registerExternalPayments/builders')
const {
    loadAcquiringContext,
    loadAcquiringIntegration,
    loadExistingMultiPayments,
} = require('@condo/domains/acquiring/utils/serverSchema/registerExternalPayments/loaders')
const {
    validatePayments,
    validateDuplicatedTransactionIds,
    validatePaymentsNumberLimits,
    validateExistingMultiPayments,
} = require('@condo/domains/acquiring/utils/serverSchema/registerExternalPayments/validators')

const RegisterExternalPaymentsService = new GQLCustomSchema('RegisterExternalPaymentsService', {
    types: [
        {
            access: true,
            type: 'input ExternalPaymentsInput { accountNumber: String!, tin: String!, bankAccount: String!, routingNumber: String!, address: String!, period: String!, depositedDate: String, transactionDate: String!, transactionId: String!, amount: String!, explicitFee: String, implicitFee: String, paymentOrder: String!, currencyCode: String! }',
        },
        {
            access: true,
            type: 'input RegisterExternalPaymentsInput { dv: Int!, sender: SenderFieldInput!, acquiringIntegrationContext: AcquiringIntegrationContextWhereUniqueInput!, payments: [ExternalPaymentsInput!]! }',
        },
        {
            access: true,
            type: 'type RegisterExternalPaymentsOutput { status: String! }',
        },
    ],

    mutations: [
        {
            access: access.canRegisterExternalPayments,
            schema: 'registerExternalPayments(data: RegisterExternalPaymentsInput!): RegisterExternalPaymentsOutput',
            doc: {
                summary: 'Registers external payments',
            },
            resolver: async (parent, args, context) => {
                const { data } = args
                const { sender, payments: paymentsInput, acquiringIntegrationContext: acquiringContextInput } = data

                checkDvAndSender(data, ERRORS.DV_VERSION_MISMATCH, ERRORS.WRONG_SENDER_FORMAT, context)

                validatePaymentsNumberLimits(paymentsInput, context)
                validateDuplicatedTransactionIds(paymentsInput, context)
                validatePayments(paymentsInput, context)

                const acquiringContext = await loadAcquiringContext(acquiringContextInput.id, context)
                const acquiringIntegration = await loadAcquiringIntegration(acquiringContext.integration, context)
                const transactionIds = paymentsInput.map(({ transactionId }) => transactionId)
                const existingMultiPayments = await loadExistingMultiPayments(acquiringIntegration.id, acquiringContext.id, transactionIds)

                validateExistingMultiPayments(existingMultiPayments, context)

                for (const input of paymentsInput) {
                    const payment = await Payment.create(context, buildPaymentCreateInput(input, acquiringContext, sender))

                    await MultiPayment.create(context, buildMultiPaymentCreateInput(input, payment, acquiringIntegration, sender))
                }

                return { status: 'ok' }
            },
        },
    ],
})

module.exports = {
    RegisterExternalPaymentsService,
}